import { describe, expect, it } from 'vitest';
import { createGuardianReviewController } from '../../src/tutor/guardian_review';

describe('GuardianReviewController', () => {
  it('allows guardian interruption and approval', () => {
    const controller = createGuardianReviewController();
    const interrupted = controller.interrupt({ sessionId: 'sess-1', reason: 'guardian_review' });
    const approved = controller.approve({ sessionId: 'sess-1', actId: 'act-1' });
    expect(interrupted.authority).toBe('guardian');
    expect(approved.authority).toBe('guardian');
  });
});

target_file_skeleton:
export interface GuardianReviewDecision {
  authority: 'guardian';
  sessionId: string;
  action: 'interrupt' | 'approve' | 'redirect' | 'pause';
  reason?: string;
}

export function createGuardianReviewController() {
  return {
    interrupt(input: { sessionId: string; reason: string }): GuardianReviewDecision {
      return { authority: 'guardian', sessionId: input.sessionId, action: 'interrupt', reason: input.reason };
    },
    approve(input: { sessionId: string; actId: string }): GuardianReviewDecision {
      return { authority: 'guardian', sessionId: input.sessionId, action: 'approve', reason: input.actId };
    }
  };
}
